const trig = $('BBR Trigger').first().json;
const agentOutput = $('BBR Research Agent').first().json;
const rawText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

let d = {};
try { d = JSON.parse(rawText); } catch(e) {}
if (!d.accountName) {
  const m = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) try { d = JSON.parse(m[1].trim()); } catch(e) {}
}
if (!d.accountName) {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) try { d = JSON.parse(m[0]); } catch(e) {}
}

const accountName = d.accountName || trig.bbrAccount || 'Customer';
const today = new Date().toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });

const slides = [];

// 1. Title
slides.push({ type:'title', title:'Backstory Business Review\n' + accountName, subtitle: today });

// 2. Agenda
slides.push({ type:'agenda', title:'Agenda', items:[
  { text:'Account at a Glance', subitems:['Engagement health','Pipeline overview'] },
  { text:'Wins & Gaps' },
  { text:'Why Backstory' },
  { text:'Enablement Plan' },
  { text:'Next Steps & Roadmap' }
]});

// 3. Stats
const stats = (d.stats || []).slice(0,3);
if (stats.length === 0 && d.engagementScore) {
  stats.push({ value: String(d.engagementScore), label:'Engagement Score', change: d.engagementTrend || '' });
}
if (stats.length > 0) {
  slides.push({ type:'stats', title:'Account at a Glance', stats });
}

// 4. Section: Account Intelligence
slides.push({ type:'section_divider', title:'Account Intelligence' });

// 5. Wins vs Gaps
slides.push({ type:'two_column', title:'Wins & Gaps',
  left:  { header:"What's Working",   items:(d.wins || ['Established relationship','Product engagement']).slice(0,5) },
  right: { header:'Gaps to Address',  items:(d.gaps || ['Expand adoption','Executive alignment']).slice(0,5) }
});

// 6. Why Backstory
const whyItems = (d.whyBackstory || []).slice(0,3);
if (whyItems.length > 0) {
  const labels = ['Value Driver 1','Value Driver 2','Value Driver 3'];
  slides.push({ type:'three_column_cards', title:'Why Backstory',
    cards: whyItems.map((why, i) => ({ title: labels[i], items:[why] }))
  });
}

// 7. Enablement Plan
const timeline = (d.enablementTimeline || []).slice(0,4);
if (timeline.length >= 2) {
  slides.push({ type:'four_column_timeline', title:'Enablement Plan',
    quarters: timeline.map((t, i) => ({
      label: 'Phase ' + (i+1),
      focus: t.split(' ').slice(0,4).join(' '),
      value: t,
      note: ''
    }))
  });
}

// 8. Section: Next Steps
slides.push({ type:'section_divider', title:'Next Steps' });

// 9. Actions + Contacts
const actionItems = (d.actionItems || []).slice(0,5)
  .map(a => a.action + (a.owner ? ' \u2014 ' + a.owner : ''));
const contacts = (d.keyContacts || []).slice(0,5)
  .map(c => c.name + (c.title ? ', ' + c.title : ''));
slides.push({ type:'two_column', title:'Next Steps',
  left:  { header:'Actions',      items: actionItems.length > 0 ? actionItems : ['Schedule follow-up','Align on success metrics'] },
  right: { header:'Key Contacts', items: contacts.length > 0 ? contacts : ['See People.ai for details'] }
});

// 10. Roadmap Placeholder
slides.push({ type:'roadmap_placeholder', title:'Product Roadmap',
  body: 'PLACEHOLDER \u2014 Insert relevant slides from the Backstory Product Roadmap.\n\nRoadmap deck:\nhttps://docs.google.com/presentation/d/1pw5YAQkmw3Xqey9bA-UYa6lyDGl5behoAbHOu9Zi7ag/edit\n\nTo complete this slide:\n1. Open the roadmap link above\n2. Copy slides relevant to this account\u2019s use case\n3. Paste them in place of this placeholder and delete it'
});

// 11. Thank You
slides.push({ type:'thank_you', title:'Thank You' });

return [{ json:{
  title: 'BBR: ' + accountName,
  slides,
  accountName,
  channelId: trig.channelId,
  assistantName: trig.assistantName || 'Aria',
  assistantEmoji: trig.assistantEmoji || ':robot_face:',
  thinkingTs: trig.thinkingTs
}}];

const slides = $('Parse BBR Data').first().json.slides;
const presId = $('Create BBR Presentation').first().json.presentationId;
const defaultSlideId = $('Create BBR Presentation').first().json.slides[0].objectId;

const EMU = (inches) => Math.round(inches * 914400);

const RGB = {
  black:       {red:0, green:0, blue:0},
  graphite:    {red:0.090, green:0.090, blue:0.129},
  surfaceGray: {red:0.733, green:0.737, blue:0.737},
  horizon:     {red:0.384, green:0.588, blue:0.678},
  white:       {red:1, green:1, blue:1},
  plum:        {red:0.667, green:0.561, blue:0.627},
  mint:        {red:0.812, green:0.980, blue:0.847},
  ember:       {red:0.816, green:0.286, blue:0.067},
  navy:        {red:0.004, green:0.173, blue:0.282},
  sky:         {red:0.131, green:0.710, blue:1},
  salmon:      {red:0.910, green:0.627, blue:0.565},
  cinder:      {red:0.753, green:0.333, blue:0.153}
};

const IMG = {
  wordmark:   'https://lh3.googleusercontent.com/d/1GMUqmxGqOLoMqsxpiUSduo2hUzE4ei_J',
  booksDark:  'https://lh3.googleusercontent.com/d/1pA1og8eOMnQE4yBT8h9z2oeGneMqCyii',
  booksWhite: 'https://lh3.googleusercontent.com/d/1cL8RmMHzCscyLIdd3Y83RaM_yVXZI6SS',
  gradient:   'https://lh3.googleusercontent.com/d/1edNwnzGIyQPv3v0D0JzpqRllAfmkIIwY'
};

const reqs = [];
const imgReqs = [];
let idC = 0;
const gid = (p) => 'bs_' + p + '_' + (idC++);

reqs.push({deleteObject: {objectId: defaultSlideId}});

function tb(sid, id, x, y, w, h) {
  reqs.push({createShape: {
    objectId: id, shapeType: 'TEXT_BOX',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}
    }
  }});
}

function ins(id, text) {
  if (!text) return;
  reqs.push({insertText: {objectId: id, text: String(text), insertionIndex: 0}});
}

function sty(id, s) {
  const ts = {};
  const f = [];
  if (s.ff) { ts.fontFamily = s.ff; f.push('fontFamily'); }
  if (s.fs) { ts.fontSize = {magnitude: s.fs, unit: 'PT'}; f.push('fontSize'); }
  if (s.b !== undefined) { ts.bold = s.b; f.push('bold'); }
  if (s.i !== undefined) { ts.italic = s.i; f.push('italic'); }
  if (s.c) { ts.foregroundColor = {opaqueColor: {rgbColor: s.c}}; f.push('foregroundColor'); }
  if (f.length === 0) return;
  reqs.push({updateTextStyle: {objectId: id, style: ts, fields: f.join(','), textRange: {type: 'ALL'}}});
}

function align(id, a) {
  reqs.push({updateParagraphStyle: {objectId: id, style: {alignment: a}, fields: 'alignment', textRange: {type: 'ALL'}}});
}

function rect(sid, id, x, y, w, h, color) {
  reqs.push({createShape: {
    objectId: id, shapeType: 'ROUND_RECTANGLE',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}
    }
  }});
  reqs.push({updateShapeProperties: {
    objectId: id,
    shapeProperties: {
      shapeBackgroundFill: {solidFill: {color: {rgbColor: color}}},
      outline: {propertyState: 'NOT_RENDERED'}
    },
    fields: 'shapeBackgroundFill,outline'
  }});
}

function banner(sid, color) {
  const id = gid('ban');
  reqs.push({createShape: {
    objectId: id, shapeType: 'RECTANGLE',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(10), unit: 'EMU'}, height: {magnitude: EMU(0.55), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(0), translateY: EMU(0), unit: 'EMU'}
    }
  }});
  reqs.push({updateShapeProperties: {
    objectId: id,
    shapeProperties: {
      shapeBackgroundFill: {solidFill: {color: {rgbColor: color}}},
      outline: {propertyState: 'NOT_RENDERED'}
    },
    fields: 'shapeBackgroundFill,outline'
  }});
  return id;
}

function colorStripe(sid, y) {
  const cs = [RGB.surfaceGray, RGB.plum, RGB.horizon, RGB.salmon, RGB.surfaceGray];
  cs.forEach((c, i) => {
    const id = gid('cs');
    reqs.push({createShape: {
      objectId: id, shapeType: 'RECTANGLE',
      elementProperties: {
        pageObjectId: sid,
        size: {width: {magnitude: EMU(2), unit: 'EMU'}, height: {magnitude: EMU(0.525), unit: 'EMU'}},
        transform: {scaleX: 1, scaleY: 1, translateX: EMU(i * 2), translateY: EMU(y), unit: 'EMU'}
      }
    }});
    reqs.push({updateShapeProperties: {
      objectId: id,
      shapeProperties: {shapeBackgroundFill: {solidFill: {color: {rgbColor: c}}}, outline: {propertyState: 'NOT_RENDERED'}},
      fields: 'shapeBackgroundFill,outline'
    }});
  });
}

function addWordmark(sid, x, y, w, h) {
  imgReqs.push({createImage: {objectId: gid('wm'), url: IMG.wordmark,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}}}});
}

function addBooksDark(sid, x, y) {
  imgReqs.push({createImage: {objectId: gid('bd'), url: IMG.booksDark,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(0.7), unit: 'EMU'}, height: {magnitude: EMU(0.55), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}}}});
}

slides.forEach((slide, idx) => {
  const sid = 'slide_' + idx;
  reqs.push({createSlide: {objectId: sid, insertionIndex: idx}});
  reqs.push({updatePageProperties: {objectId: sid,
    pageProperties: {pageBackgroundFill: {solidFill: {color: {rgbColor: RGB.white}}}},
    fields: 'pageBackgroundFill'}});

  switch (slide.type) {
    case 'title': {
      const t = gid('t'); tb(sid, t, 0.5, 0.7, 9, 2.2); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:52, b:true, c:RGB.black}); align(t, 'CENTER');
      if (slide.subtitle) {
        const s = gid('t'); tb(sid, s, 0.5, 3.0, 9, 0.65); ins(s, slide.subtitle);
        sty(s, {ff:'Cardo', fs:22, i:true, c:RGB.graphite}); align(s, 'CENTER');
      }
      addWordmark(sid, 3.5, 3.8, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    case 'agenda': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || 'Agenda');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const cid = gid('t');
      tb(sid, cid, 0.6, 1.5, 8.2, 4.0);
      const lines = [];
      const ranges = [];
      let pos = 0;
      (slide.items || []).forEach(item => {
        const text = typeof item === 'string' ? item : item.text;
        const line = '\u25CF  ' + text + '\n';
        ranges.push({start: pos, end: pos + line.length, bold: true, fs: 17, c: RGB.black});
        lines.push(line);
        pos += line.length;
        if (item.subitems) {
          item.subitems.forEach(sub => {
            const sub_line = '    \u2013  ' + sub + '\n';
            ranges.push({start: pos, end: pos + sub_line.length, bold: false, fs: 14, c: RGB.graphite});
            lines.push(sub_line);
            pos += sub_line.length;
          });
        }
      });
      reqs.push({insertText: {objectId: cid, text: lines.join(''), insertionIndex: 0}});
      ranges.forEach(r => {
        reqs.push({updateTextStyle: {
          objectId: cid,
          style: {fontFamily: 'Roboto', fontSize: {magnitude: r.fs, unit: 'PT'}, bold: r.bold,
                  foregroundColor: {opaqueColor: {rgbColor: r.c}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: r.start, endIndex: r.end}
        }});
      });
      addBooksDark(sid, 8.8, 4.6);
      break;
    }
    case 'section_divider': {
      const t = gid('t'); tb(sid, t, 0.5, 1.4, 9, 2.0); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:52, b:true, c:RGB.black}); align(t, 'CENTER');
      addWordmark(sid, 3.5, 3.8, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    case 'stats': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || 'Key Metrics');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const pos = [0.4, 3.5, 6.6];
      (slide.stats || []).slice(0,3).forEach((st, i) => {
        const cid = gid('t');
        tb(sid, cid, pos[i], 1.6, 3.0, 3.5);
        const vLine = (st.value || '') + '\n';
        const lLine = (st.label || '') + '\n';
        const cLine = st.change || '';
        const full = vLine + lLine + cLine;
        reqs.push({insertText: {objectId: cid, text: full, insertionIndex: 0}});
        reqs.push({updateTextStyle: {objectId: cid,
          style: {fontFamily: 'Cardo', fontSize: {magnitude: 28, unit: 'PT'}, bold: true,
                  foregroundColor: {opaqueColor: {rgbColor: RGB.navy}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: 0, endIndex: vLine.length}}});
        reqs.push({updateTextStyle: {objectId: cid,
          style: {fontFamily: 'Roboto', fontSize: {magnitude: 15, unit: 'PT'}, bold: false,
                  foregroundColor: {opaqueColor: {rgbColor: RGB.graphite}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: vLine.length, endIndex: vLine.length + lLine.length}}});
        if (st.change) {
          reqs.push({updateTextStyle: {objectId: cid,
            style: {fontFamily: 'Roboto', fontSize: {magnitude: 14, unit: 'PT'}, bold: true,
                    foregroundColor: {opaqueColor: {rgbColor: RGB.horizon}}},
            fields: 'fontFamily,fontSize,bold,foregroundColor',
            textRange: {type: 'FIXED_RANGE', startIndex: vLine.length + lLine.length, endIndex: full.length}}});
        }
        reqs.push({updateParagraphStyle: {objectId: cid,
          style: {alignment: 'CENTER'}, fields: 'alignment', textRange: {type: 'ALL'}}});
      });
      addBooksDark(sid, 8.8, 4.6);
      break;
    }
    case 'two_column': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      [{d:slide.left, x:0.5, clr:RGB.horizon}, {d:slide.right, x:5.2, clr:RGB.ember}].forEach(col => {
        if (!col.d) return;
        const h = gid('t'); tb(sid, h, col.x, 1.5, 4.2, 0.55); ins(h, col.d.header || '');
        sty(h, {ff:'Roboto', fs:22, b:true, c:col.clr});
        const items = (col.d.items || []).map(it => '\u2022 ' + it).join('\n');
        const b = gid('t'); tb(sid, b, col.x, 2.1, 4.2, 3.1); ins(b, items);
        sty(b, {ff:'Roboto', fs:16, c:RGB.graphite});
      });
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
    case 'three_column_cards': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 9.0, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const cx = [0.7, 3.7, 6.7]; const cc = [RGB.horizon, RGB.plum, RGB.ember];
      (slide.cards || []).slice(0,3).forEach((card, i) => {
        const ct = gid('t'); tb(sid, ct, cx[i], 1.45, 2.6, 0.45); ins(ct, card.title || '');
        sty(ct, {ff:'Roboto', fs:15, b:true, c:RGB.black});
        rect(sid, gid('r'), cx[i], 1.92, 2.6, 3.35, cc[i]);
        const items = (card.items || []).map(it => '\u2022 ' + it).join('\n');
        const ci = gid('t'); tb(sid, ci, cx[i]+0.15, 2.05, 2.3, 3.1); ins(ci, items);
        sty(ci, {ff:'Roboto', fs:13, c:RGB.white});
      });
      addBooksDark(sid, 9.1, 4.85);
      break;
    }
    case 'four_column_timeline': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 9.0, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const qx = [0.6, 2.8, 5.0, 7.2]; const qc = [RGB.horizon, RGB.plum, RGB.ember, RGB.navy];
      (slide.quarters || []).slice(0,4).forEach((q, i) => {
        const ql = gid('t'); tb(sid, ql, qx[i], 1.45, 2.0, 0.45); ins(ql, q.label || '');
        sty(ql, {ff:'Roboto', fs:15, b:true, c:RGB.black}); align(ql, 'CENTER');
        rect(sid, gid('r'), qx[i], 1.95, 2.0, 2.9, qc[i]);
        const fl = gid('t'); tb(sid, fl, qx[i], 2.1, 2.0, 0.32); ins(fl, 'Focus Area');
        sty(fl, {ff:'Roboto', fs:10, c:RGB.white}); align(fl, 'CENTER');
        const fv = gid('t'); tb(sid, fv, qx[i], 2.45, 2.0, 0.85); ins(fv, q.focus || q.value || '');
        sty(fv, {ff:'Cardo', fs:16, b:true, c:RGB.white}); align(fv, 'CENTER');
        if (q.note) {
          const n = gid('t'); tb(sid, n, qx[i], 3.95, 2.0, 0.4); ins(n, q.note);
          sty(n, {ff:'Roboto', fs:11, c:RGB.white}); align(n, 'CENTER');
        }
      });
      addBooksDark(sid, 9.1, 4.85);
      break;
    }
    case 'roadmap_placeholder': {
      // Cinder warning banner across top
      banner(sid, RGB.cinder);
      const bt = gid('t'); tb(sid, bt, 0.25, 0.12, 9.5, 0.35);
      ins(bt, '\u26A0\uFE0F  PLACEHOLDER \u2014 Insert relevant roadmap slides here before presenting');
      sty(bt, {ff:'Roboto', fs:13, b:true, c:RGB.white});
      // Title
      const t = gid('t'); tb(sid, t, 0.5, 0.75, 8.5, 0.9); ins(t, slide.title || 'Product Roadmap');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      // Body
      const b = gid('t'); tb(sid, b, 0.5, 1.75, 9.0, 3.5); ins(b, slide.body || '');
      sty(b, {ff:'Roboto', fs:15, c:RGB.graphite});
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
    case 'thank_you': {
      const t = gid('t'); tb(sid, t, 0.5, 1.8, 9, 1.5);
      ins(t, (slide.title || 'THANK YOU').toUpperCase());
      sty(t, {ff:'Cardo', fs:72, b:true, c:RGB.black}); align(t, 'CENTER');
      addWordmark(sid, 3.5, 3.5, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    default: {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      if (slide.body) {
        const b = gid('t'); tb(sid, b, 0.5, 1.6, 9, 3.5); ins(b, slide.body);
        sty(b, {ff:'Roboto', fs:18, c:RGB.graphite});
      }
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
  }
});

return [{ json: { requests: reqs, imageRequests: imgReqs, presentationId: presId } }];

const trig = $('BBR Trigger').first().json;
const agentOutput = $('BBR Research Agent').first().json;
const rawText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);

let d = {};
try { d = JSON.parse(rawText); } catch(e) {}
if (!d.accountName) {
  const m = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) try { d = JSON.parse(m[1].trim()); } catch(e) {}
}
if (!d.accountName) {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) try { d = JSON.parse(m[0]); } catch(e) {}
}

const accountName = d.accountName || trig.bbrAccount || 'Customer';
const today = new Date().toLocaleDateString('en-US', { year:'numeric', month:'long', day:'numeric' });

const slides = [];

// 1. Title
slides.push({ type:'title', title:'Backstory Business Review\n' + accountName, subtitle: today });

// 2. Agenda
slides.push({ type:'agenda', title:'Agenda', items:[
  { text:'Account at a Glance', subitems:['Engagement health','Pipeline overview'] },
  { text:'Wins & Gaps' },
  { text:'Why Backstory' },
  { text:'Enablement Plan' },
  { text:'Next Steps & Roadmap' }
]});

// 3. Stats
const stats = (d.stats || []).slice(0,3);
if (stats.length === 0 && d.engagementScore) {
  stats.push({ value: String(d.engagementScore), label:'Engagement Score', change: d.engagementTrend || '' });
}
if (stats.length > 0) {
  slides.push({ type:'stats', title:'Account at a Glance', stats });
}

// 4. Section: Account Intelligence
slides.push({ type:'section_divider', title:'Account Intelligence' });

// 5. Wins vs Gaps
slides.push({ type:'two_column', title:'Wins & Gaps',
  left:  { header:"What's Working",   items:(d.wins || ['Established relationship','Product engagement']).slice(0,5) },
  right: { header:'Gaps to Address',  items:(d.gaps || ['Expand adoption','Executive alignment']).slice(0,5) }
});

// 6. Why Backstory
const whyItems = (d.whyBackstory || []).slice(0,3);
if (whyItems.length > 0) {
  const labels = ['Value Driver 1','Value Driver 2','Value Driver 3'];
  slides.push({ type:'three_column_cards', title:'Why Backstory',
    cards: whyItems.map((why, i) => ({ title: labels[i], items:[why] }))
  });
}

// 7. Enablement Plan
const timeline = (d.enablementTimeline || []).slice(0,4);
if (timeline.length >= 2) {
  slides.push({ type:'four_column_timeline', title:'Enablement Plan',
    quarters: timeline.map((t, i) => ({
      label: 'Phase ' + (i+1),
      focus: t.split(' ').slice(0,4).join(' '),
      value: t,
      note: ''
    }))
  });
}

// 8. Section: Next Steps
slides.push({ type:'section_divider', title:'Next Steps' });

// 9. Actions + Contacts
const actionItems = (d.actionItems || []).slice(0,5)
  .map(a => a.action + (a.owner ? ' \u2014 ' + a.owner : ''));
const contacts = (d.keyContacts || []).slice(0,5)
  .map(c => c.name + (c.title ? ', ' + c.title : ''));
slides.push({ type:'two_column', title:'Next Steps',
  left:  { header:'Actions',      items: actionItems.length > 0 ? actionItems : ['Schedule follow-up','Align on success metrics'] },
  right: { header:'Key Contacts', items: contacts.length > 0 ? contacts : ['See People.ai for details'] }
});

// 10. Roadmap Placeholder
slides.push({ type:'roadmap_placeholder', title:'Product Roadmap',
  body: 'PLACEHOLDER \u2014 Insert relevant slides from the Backstory Product Roadmap.\n\nRoadmap deck:\nhttps://docs.google.com/presentation/d/1pw5YAQkmw3Xqey9bA-UYa6lyDGl5behoAbHOu9Zi7ag/edit\n\nTo complete this slide:\n1. Open the roadmap link above\n2. Copy slides relevant to this account\u2019s use case\n3. Paste them in place of this placeholder and delete it'
});

// 11. Thank You
slides.push({ type:'thank_you', title:'Thank You' });

return [{ json:{
  title: 'BBR: ' + accountName,
  slides,
  accountName,
  channelId: trig.channelId,
  assistantName: trig.assistantName || 'Aria',
  assistantEmoji: trig.assistantEmoji || ':robot_face:',
  thinkingTs: trig.thinkingTs
}}];

const slides = $('Parse BBR Data').first().json.slides;
const presId = $('Create BBR Presentation').first().json.presentationId;
const defaultSlideId = $('Create BBR Presentation').first().json.slides[0].objectId;

const EMU = (inches) => Math.round(inches * 914400);

const RGB = {
  black:       {red:0, green:0, blue:0},
  graphite:    {red:0.090, green:0.090, blue:0.129},
  surfaceGray: {red:0.733, green:0.737, blue:0.737},
  horizon:     {red:0.384, green:0.588, blue:0.678},
  white:       {red:1, green:1, blue:1},
  plum:        {red:0.667, green:0.561, blue:0.627},
  mint:        {red:0.812, green:0.980, blue:0.847},
  ember:       {red:0.816, green:0.286, blue:0.067},
  navy:        {red:0.004, green:0.173, blue:0.282},
  sky:         {red:0.131, green:0.710, blue:1},
  salmon:      {red:0.910, green:0.627, blue:0.565},
  cinder:      {red:0.753, green:0.333, blue:0.153}
};

const IMG = {
  wordmark:   'https://lh3.googleusercontent.com/d/1GMUqmxGqOLoMqsxpiUSduo2hUzE4ei_J',
  booksDark:  'https://lh3.googleusercontent.com/d/1pA1og8eOMnQE4yBT8h9z2oeGneMqCyii',
  booksWhite: 'https://lh3.googleusercontent.com/d/1cL8RmMHzCscyLIdd3Y83RaM_yVXZI6SS',
  gradient:   'https://lh3.googleusercontent.com/d/1edNwnzGIyQPv3v0D0JzpqRllAfmkIIwY'
};

const reqs = [];
const imgReqs = [];
let idC = 0;
const gid = (p) => 'bs_' + p + '_' + (idC++);

reqs.push({deleteObject: {objectId: defaultSlideId}});

function tb(sid, id, x, y, w, h) {
  reqs.push({createShape: {
    objectId: id, shapeType: 'TEXT_BOX',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}
    }
  }});
}

function ins(id, text) {
  if (!text) return;
  reqs.push({insertText: {objectId: id, text: String(text), insertionIndex: 0}});
}

function sty(id, s) {
  const ts = {};
  const f = [];
  if (s.ff) { ts.fontFamily = s.ff; f.push('fontFamily'); }
  if (s.fs) { ts.fontSize = {magnitude: s.fs, unit: 'PT'}; f.push('fontSize'); }
  if (s.b !== undefined) { ts.bold = s.b; f.push('bold'); }
  if (s.i !== undefined) { ts.italic = s.i; f.push('italic'); }
  if (s.c) { ts.foregroundColor = {opaqueColor: {rgbColor: s.c}}; f.push('foregroundColor'); }
  if (f.length === 0) return;
  reqs.push({updateTextStyle: {objectId: id, style: ts, fields: f.join(','), textRange: {type: 'ALL'}}});
}

function align(id, a) {
  reqs.push({updateParagraphStyle: {objectId: id, style: {alignment: a}, fields: 'alignment', textRange: {type: 'ALL'}}});
}

function rect(sid, id, x, y, w, h, color) {
  reqs.push({createShape: {
    objectId: id, shapeType: 'ROUND_RECTANGLE',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}
    }
  }});
  reqs.push({updateShapeProperties: {
    objectId: id,
    shapeProperties: {
      shapeBackgroundFill: {solidFill: {color: {rgbColor: color}}},
      outline: {propertyState: 'NOT_RENDERED'}
    },
    fields: 'shapeBackgroundFill,outline'
  }});
}

function banner(sid, color) {
  const id = gid('ban');
  reqs.push({createShape: {
    objectId: id, shapeType: 'RECTANGLE',
    elementProperties: {
      pageObjectId: sid,
      size: {width: {magnitude: EMU(10), unit: 'EMU'}, height: {magnitude: EMU(0.55), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(0), translateY: EMU(0), unit: 'EMU'}
    }
  }});
  reqs.push({updateShapeProperties: {
    objectId: id,
    shapeProperties: {
      shapeBackgroundFill: {solidFill: {color: {rgbColor: color}}},
      outline: {propertyState: 'NOT_RENDERED'}
    },
    fields: 'shapeBackgroundFill,outline'
  }});
  return id;
}

function colorStripe(sid, y) {
  const cs = [RGB.surfaceGray, RGB.plum, RGB.horizon, RGB.salmon, RGB.surfaceGray];
  cs.forEach((c, i) => {
    const id = gid('cs');
    reqs.push({createShape: {
      objectId: id, shapeType: 'RECTANGLE',
      elementProperties: {
        pageObjectId: sid,
        size: {width: {magnitude: EMU(2), unit: 'EMU'}, height: {magnitude: EMU(0.525), unit: 'EMU'}},
        transform: {scaleX: 1, scaleY: 1, translateX: EMU(i * 2), translateY: EMU(y), unit: 'EMU'}
      }
    }});
    reqs.push({updateShapeProperties: {
      objectId: id,
      shapeProperties: {shapeBackgroundFill: {solidFill: {color: {rgbColor: c}}}, outline: {propertyState: 'NOT_RENDERED'}},
      fields: 'shapeBackgroundFill,outline'
    }});
  });
}

function addWordmark(sid, x, y, w, h) {
  imgReqs.push({createImage: {objectId: gid('wm'), url: IMG.wordmark,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(w), unit: 'EMU'}, height: {magnitude: EMU(h), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}}}});
}

function addBooksDark(sid, x, y) {
  imgReqs.push({createImage: {objectId: gid('bd'), url: IMG.booksDark,
    elementProperties: {pageObjectId: sid,
      size: {width: {magnitude: EMU(0.7), unit: 'EMU'}, height: {magnitude: EMU(0.55), unit: 'EMU'}},
      transform: {scaleX: 1, scaleY: 1, translateX: EMU(x), translateY: EMU(y), unit: 'EMU'}}}});
}

slides.forEach((slide, idx) => {
  const sid = 'slide_' + idx;
  reqs.push({createSlide: {objectId: sid, insertionIndex: idx}});
  reqs.push({updatePageProperties: {objectId: sid,
    pageProperties: {pageBackgroundFill: {solidFill: {color: {rgbColor: RGB.white}}}},
    fields: 'pageBackgroundFill'}});

  switch (slide.type) {
    case 'title': {
      const t = gid('t'); tb(sid, t, 0.5, 0.7, 9, 2.2); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:52, b:true, c:RGB.black}); align(t, 'CENTER');
      if (slide.subtitle) {
        const s = gid('t'); tb(sid, s, 0.5, 3.0, 9, 0.65); ins(s, slide.subtitle);
        sty(s, {ff:'Cardo', fs:22, i:true, c:RGB.graphite}); align(s, 'CENTER');
      }
      addWordmark(sid, 3.5, 3.8, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    case 'agenda': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || 'Agenda');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const cid = gid('t');
      tb(sid, cid, 0.6, 1.5, 8.2, 4.0);
      const lines = [];
      const ranges = [];
      let pos = 0;
      (slide.items || []).forEach(item => {
        const text = typeof item === 'string' ? item : item.text;
        const line = '\u25CF  ' + text + '\n';
        ranges.push({start: pos, end: pos + line.length, bold: true, fs: 17, c: RGB.black});
        lines.push(line);
        pos += line.length;
        if (item.subitems) {
          item.subitems.forEach(sub => {
            const sub_line = '    \u2013  ' + sub + '\n';
            ranges.push({start: pos, end: pos + sub_line.length, bold: false, fs: 14, c: RGB.graphite});
            lines.push(sub_line);
            pos += sub_line.length;
          });
        }
      });
      reqs.push({insertText: {objectId: cid, text: lines.join(''), insertionIndex: 0}});
      ranges.forEach(r => {
        reqs.push({updateTextStyle: {
          objectId: cid,
          style: {fontFamily: 'Roboto', fontSize: {magnitude: r.fs, unit: 'PT'}, bold: r.bold,
                  foregroundColor: {opaqueColor: {rgbColor: r.c}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: r.start, endIndex: r.end}
        }});
      });
      addBooksDark(sid, 8.8, 4.6);
      break;
    }
    case 'section_divider': {
      const t = gid('t'); tb(sid, t, 0.5, 1.4, 9, 2.0); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:52, b:true, c:RGB.black}); align(t, 'CENTER');
      addWordmark(sid, 3.5, 3.8, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    case 'stats': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || 'Key Metrics');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const pos = [0.4, 3.5, 6.6];
      (slide.stats || []).slice(0,3).forEach((st, i) => {
        const cid = gid('t');
        tb(sid, cid, pos[i], 1.6, 3.0, 3.5);
        const vLine = (st.value || '') + '\n';
        const lLine = (st.label || '') + '\n';
        const cLine = st.change || '';
        const full = vLine + lLine + cLine;
        reqs.push({insertText: {objectId: cid, text: full, insertionIndex: 0}});
        reqs.push({updateTextStyle: {objectId: cid,
          style: {fontFamily: 'Cardo', fontSize: {magnitude: 28, unit: 'PT'}, bold: true,
                  foregroundColor: {opaqueColor: {rgbColor: RGB.navy}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: 0, endIndex: vLine.length}}});
        reqs.push({updateTextStyle: {objectId: cid,
          style: {fontFamily: 'Roboto', fontSize: {magnitude: 15, unit: 'PT'}, bold: false,
                  foregroundColor: {opaqueColor: {rgbColor: RGB.graphite}}},
          fields: 'fontFamily,fontSize,bold,foregroundColor',
          textRange: {type: 'FIXED_RANGE', startIndex: vLine.length, endIndex: vLine.length + lLine.length}}});
        if (st.change) {
          reqs.push({updateTextStyle: {objectId: cid,
            style: {fontFamily: 'Roboto', fontSize: {magnitude: 14, unit: 'PT'}, bold: true,
                    foregroundColor: {opaqueColor: {rgbColor: RGB.horizon}}},
            fields: 'fontFamily,fontSize,bold,foregroundColor',
            textRange: {type: 'FIXED_RANGE', startIndex: vLine.length + lLine.length, endIndex: full.length}}});
        }
        reqs.push({updateParagraphStyle: {objectId: cid,
          style: {alignment: 'CENTER'}, fields: 'alignment', textRange: {type: 'ALL'}}});
      });
      addBooksDark(sid, 8.8, 4.6);
      break;
    }
    case 'two_column': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      [{d:slide.left, x:0.5, clr:RGB.horizon}, {d:slide.right, x:5.2, clr:RGB.ember}].forEach(col => {
        if (!col.d) return;
        const h = gid('t'); tb(sid, h, col.x, 1.5, 4.2, 0.55); ins(h, col.d.header || '');
        sty(h, {ff:'Roboto', fs:22, b:true, c:col.clr});
        const items = (col.d.items || []).map(it => '\u2022 ' + it).join('\n');
        const b = gid('t'); tb(sid, b, col.x, 2.1, 4.2, 3.1); ins(b, items);
        sty(b, {ff:'Roboto', fs:16, c:RGB.graphite});
      });
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
    case 'three_column_cards': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 9.0, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const cx = [0.7, 3.7, 6.7]; const cc = [RGB.horizon, RGB.plum, RGB.ember];
      (slide.cards || []).slice(0,3).forEach((card, i) => {
        const ct = gid('t'); tb(sid, ct, cx[i], 1.45, 2.6, 0.45); ins(ct, card.title || '');
        sty(ct, {ff:'Roboto', fs:15, b:true, c:RGB.black});
        rect(sid, gid('r'), cx[i], 1.92, 2.6, 3.35, cc[i]);
        const items = (card.items || []).map(it => '\u2022 ' + it).join('\n');
        const ci = gid('t'); tb(sid, ci, cx[i]+0.15, 2.05, 2.3, 3.1); ins(ci, items);
        sty(ci, {ff:'Roboto', fs:13, c:RGB.white});
      });
      addBooksDark(sid, 9.1, 4.85);
      break;
    }
    case 'four_column_timeline': {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 9.0, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      const qx = [0.6, 2.8, 5.0, 7.2]; const qc = [RGB.horizon, RGB.plum, RGB.ember, RGB.navy];
      (slide.quarters || []).slice(0,4).forEach((q, i) => {
        const ql = gid('t'); tb(sid, ql, qx[i], 1.45, 2.0, 0.45); ins(ql, q.label || '');
        sty(ql, {ff:'Roboto', fs:15, b:true, c:RGB.black}); align(ql, 'CENTER');
        rect(sid, gid('r'), qx[i], 1.95, 2.0, 2.9, qc[i]);
        const fl = gid('t'); tb(sid, fl, qx[i], 2.1, 2.0, 0.32); ins(fl, 'Focus Area');
        sty(fl, {ff:'Roboto', fs:10, c:RGB.white}); align(fl, 'CENTER');
        const fv = gid('t'); tb(sid, fv, qx[i], 2.45, 2.0, 0.85); ins(fv, q.focus || q.value || '');
        sty(fv, {ff:'Cardo', fs:16, b:true, c:RGB.white}); align(fv, 'CENTER');
        if (q.note) {
          const n = gid('t'); tb(sid, n, qx[i], 3.95, 2.0, 0.4); ins(n, q.note);
          sty(n, {ff:'Roboto', fs:11, c:RGB.white}); align(n, 'CENTER');
        }
      });
      addBooksDark(sid, 9.1, 4.85);
      break;
    }
    case 'roadmap_placeholder': {
      // Cinder warning banner across top
      banner(sid, RGB.cinder);
      const bt = gid('t'); tb(sid, bt, 0.25, 0.12, 9.5, 0.35);
      ins(bt, '\u26A0\uFE0F  PLACEHOLDER \u2014 Insert relevant roadmap slides here before presenting');
      sty(bt, {ff:'Roboto', fs:13, b:true, c:RGB.white});
      // Title
      const t = gid('t'); tb(sid, t, 0.5, 0.75, 8.5, 0.9); ins(t, slide.title || 'Product Roadmap');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      // Body
      const b = gid('t'); tb(sid, b, 0.5, 1.75, 9.0, 3.5); ins(b, slide.body || '');
      sty(b, {ff:'Roboto', fs:15, c:RGB.graphite});
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
    case 'thank_you': {
      const t = gid('t'); tb(sid, t, 0.5, 1.8, 9, 1.5);
      ins(t, (slide.title || 'THANK YOU').toUpperCase());
      sty(t, {ff:'Cardo', fs:72, b:true, c:RGB.black}); align(t, 'CENTER');
      addWordmark(sid, 3.5, 3.5, 3.0, 0.5);
      colorStripe(sid, 5.1);
      break;
    }
    default: {
      const t = gid('t'); tb(sid, t, 0.5, 0.3, 8.5, 1.1); ins(t, slide.title || '');
      sty(t, {ff:'Cardo', fs:34, b:true, c:RGB.black});
      if (slide.body) {
        const b = gid('t'); tb(sid, b, 0.5, 1.6, 9, 3.5); ins(b, slide.body);
        sty(b, {ff:'Roboto', fs:18, c:RGB.graphite});
      }
      addBooksDark(sid, 8.85, 4.65);
      break;
    }
  }
});

return [{ json: { requests: reqs, imageRequests: imgReqs, presentationId: presId } }];
